-- ESAT Papers (2016-2023) — ENGAA-based, Part B even Qs removed per ESAT spec

-- ESAT 2016 (24 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2016', 1, 2016, 'October', 80, 24, '["esat"]', '[{"id": "esat2016q1", "num": 1, "text": "ESAT 2016 Question 1", "question_text": "Find the complete set of solutions to −8<6−x2", "options": ["x<4", "x>4", "x<20", "x>20", "x<22", "x>22", "x<28", "x>28"], "answer": 6, "topic": "esat"}, {"id": "esat2016q3", "num": 3, "text": "ESAT 2016 Question 3", "question_text": "Which one of the following is a simplification of (3√−2√)2 ? 81−23√2√", "options": ["5−22√3√", "23√−22√", "1", "5−2√3√"], "answer": 1, "topic": "esat"}, {"id": "esat2016q5", "num": 5, "text": "ESAT 2016 Question 5", "question_text": "The ratio of Q:R is 5:2 and the ratio of R:S is 3:10 Which one of the following gives the ratio Q:S in its simplest form?", "options": ["1:2", "2:1", "3:4", "3:25", "4:3", "25:3"], "answer": 2, "topic": "esat"}, {"id": "esat2016q6", "num": 6, "text": "ESAT 2016 Question 6", "question_text": "A uranium-235 nucleus can undergo fission to produce two smaller nuclei. Which of the diagrams, if any, could represent this process? ![6_204_302_1042_704_0.jpg](images/6_204_302_1042_704_0.jpg)", "options": ["none of them", "1 only", "2 only", "3 only", "1 and 2 only", "1 and 3 only", "2 and 3 only", "1,2 and 3"], "answer": 2, "topic": "esat"}, {"id": "esat2016q7", "num": 7, "text": "ESAT 2016 Question 7", "question_text": "The mean age of the twenty members of a running club is exactly 28. The mean age increases by exactly 2 years when two new members join. What is the mean age of the two new members?", "options": ["20 years", "22 years", "30 years", "40 years", "50 years", "52 years"], "answer": 4, "topic": "esat"}, {"id": "esat2016q8", "num": 8, "text": "ESAT 2016 Question 8", "question_text": "A circuit consists of a 5.0Ω resistor and a variable resistor connected in series with a 24 V battery. The variable resistor has a minimum resistance of 3.0Ω and a maximum resistance of 15Ω . The battery and the connecting wires have negligible resistance. What is the maximum power dissipated in the 5.0Ω resistor?", "options": ["7.2W", "18W", "27 W", "45 W", "72W", "75W"], "answer": 3, "topic": "esat"}, {"id": "esat2016q9", "num": 9, "text": "ESAT 2016 Question 9", "question_text": "A medical scanner is bought for £15000. The value of the scanner depreciates by 20% every year. By how much has the scanner reduced in value after 2 years?", "options": ["£600", "£3000", "£5400", "£6000", "£9000", "£9600", "£12000"], "answer": 2, "topic": "esat"}, {"id": "esat2016q10", "num": 10, "text": "ESAT 2016 Question 10", "question_text": "The total power P radiated by a star is given by: P=kR2T4 where R is the radius of the star, T is its surface temperature and k is a constant. The power currently radiated by the Sun is 4.0×1026W . Towards the end of the Sun’s life its radius will increase by a factor of a hundred and its surface temperature will decrease by a factor of two. What will be the power radiated by the Sun when these changes have occurred?", "options": ["2.5×1027W", "1.0×1028W", "2.0×1028W", "2.5×1029W", "1.0×1030W", "2.0×1030W", "2.5×1033W", "1.0×1034W"], "answer": 3, "topic": "esat"}, {"id": "esat2016q11", "num": 11, "text": "ESAT 2016 Question 11", "question_text": "The point A is 4km due East of the point B. The bearing of the point C from A is 330° and the bearing of C from B is 060° Find the distance BC.", "options": ["2km", "23√km", "4km", "25√km", "42√km"], "answer": 1, "topic": "esat"}, {"id": "esat2016q12", "num": 12, "text": "ESAT 2016 Question 12", "question_text": "A transverse wave travelling through a medium has a frequency of 5.0Hz , a wavelength of 4.0cm and an amplitude of 3.0cm . What is the total distance travelled by a particle of the medium in one minute?", "options": ["900cm", "1200cm", "1800cm", "2400cm", "3600cm", "4800 cm"], "answer": 4, "topic": "esat"}, {"id": "esat2016q13", "num": 13, "text": "ESAT 2016 Question 13", "question_text": "The quantities x and y are positive. x is inversely proportional to the square root of y . When x=8, y=9 . What is the value of y when x=6 ?", "options": ["32", "2", "8116", "2714", "12", "16"], "answer": 5, "topic": "esat"}, {"id": "esat2016q14", "num": 14, "text": "ESAT 2016 Question 14", "question_text": "A motor is used to lift a mass of 5.0kg using a pulley system as shown in the diagram. The pulley is secured to the roof using a coupling. ![11_493_266_727_595_0.jpg](images/11_493_266_727_595_0.jpg) The motor needs to cause the mass to accelerate upwards at 0.80ms−2 . What is the minimum tension force that the coupling must be able to withstand without breaking? (The gravitational field strength g is 10Nkg−1 . The pulley system is frictionless and has negligible mass. The rope has negligible ma", "options": ["4.0N", "8.0N", "46N", "50N", "54 N", "92 N", "104N", "108N"], "answer": 7, "topic": "esat"}, {"id": "esat2016q15", "num": 15, "text": "ESAT 2016 Question 15", "question_text": "In a trapezium PQRS , the parallel sides are PQ and RS . PQ=(x−1)cm, RS=(x+5)cm and the vertical height QR=xcm . ![12_209_315_389_234_0.jpg](images/12_209_315_389_234_0.jpg) [diagram not to scale] The area of the trapezium is 120cm2 . What is the length of RS ?", "options": ["9 cm", "10 cm", "11cm", "12cm", "15cm", "17 cm"], "answer": 4, "topic": "esat"}, {"id": "esat2016q17", "num": 17, "text": "ESAT 2016 Question 17", "question_text": "Make b the subject of the formula: a=b2+23b2−1", "options": ["b=±(a+23a+1)√", "b=±(a+23a−1)√", "b=±(2−a3a+1)√", "b=±(2−a3a−1)√", "b=±(33a+1)√", "b=±(33a−1)√"], "answer": 1, "topic": "esat"}, {"id": "esat2016q18", "num": 18, "text": "ESAT 2016 Question 18", "question_text": "A cubic block has a hole through it with a square cross-section. The dimensions are shown on the diagram. The weight of the block is 30N . ![15_664_269_403_464_0.jpg](images/15_664_269_403_464_0.jpg) What is the density of the material from which the block is made? (The gravitational field strength g is 10Nkg−1 .)", "options": ["0.30gcm−3", "0.40gcm−3", "0.60gcm−3", "1.2gcm−3", "3.0 gcm−3", "4.0gc m−3", "6.0gcm−3", "12gc m−3"], "answer": 5, "topic": "esat"}, {"id": "esat2016q36", "num": 36, "text": "ESAT 2016 Question 36", "question_text": "of the students chose tennis, and 23 of these were boys; 25 girls chose swimming, and 27 students chose archery.", "options": ["320", "937", "415", "1637", "3257"], "answer": 0, "topic": "esat"}, {"id": "esat2016q25", "num": 25, "text": "ESAT 2016 Question 25", "question_text": "Which one of the following expressions is equivalent to 92n+1×34−3n272−n ?", "options": ["39", "3−2n", "32−2n", "34n", "36n−2", "36"], "answer": 3, "topic": "esat"}, {"id": "esat2016q27", "num": 27, "text": "ESAT 2016 Question 27", "question_text": "In the diagram below, PQRS is part of a regular polygon. The polygon has n sides. The side PQ is extended to T such that PQT is a straight line. The length of RQ is the same as the length of RT . ![23_475_456_667_542_0.jpg](images/23_475_456_667_542_0.jpg) Find an equation for n in terms of x , where x is the size of angle ∠ QRT in degrees.", "options": ["n=180x−90", "n=180−x720", "n=360−x90", "n=360180−x", "n=720180−x", "n=720360−x", "n=360360−x"], "answer": 4, "topic": "esat"}, {"id": "esat2016q28", "num": 28, "text": "ESAT 2016 Question 28", "question_text": "A student carries out an experiment to measure the speed of sound. A loudspeaker that emits sound in all directions is placed between two buildings that are 128m apart as shown. The student and loudspeaker are 48m from one of the buildings. ![24_292_334_1145_328_0.jpg](images/24_292_334_1145_328_0.jpg) The loudspeaker is connected to a signal generator that causes it to emit regular clicks. The student notices that each click results in two echoes, one from each building. The rate at which the c", "options": ["2.0Hz", "2.5Hz", "3.3Hz", "4.0Hz", "5.3Hz", "6.7Hz", "10Hz"], "answer": 6, "topic": "esat"}, {"id": "esat2016q33", "num": 33, "text": "ESAT 2016 Question 33", "question_text": "The first term of a convergent geometric series is 8 . The fifth term is 2. The sixth term is real and positive. What is the sum to infinity of this series? (The sum to infinity of a convergent geometric series is given by a1−r , where a is the first term and r is the common ratio.)", "options": ["8(1+2√)", "8(1−2√)", "8(2+2√)", "8(2−2√)", "16", "845√45√−1", "845√544√+1"], "answer": 2, "topic": "esat"}, {"id": "esat2016q43", "num": 43, "text": "ESAT 2016 Question 43", "question_text": "f(x)=x3−a2x where a is a positive constant. Find the complete set of values of x for which f(x) is an increasing function.", "options": ["x≤−a, x≥a", "−a≤x≤a", "x≤−a,0≤x≤a", "−a≤x≤0, x≥a", "x≤−a3, x≥a3", "−a3≤x≤a3", "x≤−a3, x≥a3", "−a3≤x≤a3"], "answer": 6, "topic": "esat"}, {"id": "esat2016q49", "num": 49, "text": "ESAT 2016 Question 49", "question_text": "A cursor starts at the point (0,10) and moves parallel to the x -axis in the negative direction. What is the minimum distance parallel to the y -axis between the cursor and the graph of y=4x3−12x2−36x−15?", "options": ["0", "5", "25", "69", "133"], "answer": 1, "topic": "esat"}, {"id": "esat2016q51", "num": 51, "text": "ESAT 2016 Question 51", "question_text": "What is the area enclosed by the line x=7 and the curve x=3(y−1)2+4 ?", "options": ["4", "8", "10", "11", "14", "20"], "answer": 0, "topic": "esat"}, {"id": "esat2016q53", "num": 53, "text": "ESAT 2016 Question 53", "question_text": "A curve has equation y=3x4−4x3−12x2+20 What is the complete set of values of the constant k for which the equation 3x4−4x3−12x2+20=k has exactly four distinct real roots?", "options": ["no values of k", "−12<k<15", "15<k<20", "k>20", "7<k<20", "all values of k"], "answer": 2, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;

-- ESAT 2017 (25 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2017', 1, 2017, 'October', 80, 25, '["esat"]', '[{"id": "esat2017q1", "num": 1, "text": "ESAT 2017 Question 1", "question_text": "Evaluate (12√+3√)2(12√−3√)2", "options": ["1", "3", "53", "73", "33√", "9"], "answer": 5, "topic": "esat"}, {"id": "esat2017q2", "num": 2, "text": "ESAT 2017 Question 2", "question_text": "A car is travelling along a horizontal road in a straight line. The graph is a velocity-time graph for part of the car's journey. ![42_284_297_1303_610_0.jpg](images/42_284_297_1303_610_0.jpg) During this part of the journey, what is the total distance that the car travels while it is decelerating?", "options": ["400m", "500m", "550m", "600m", "750m", "1400m", "1800 m", "1900 m"], "answer": 1, "topic": "esat"}, {"id": "esat2017q3", "num": 3, "text": "ESAT 2017 Question 3", "question_text": "Solve fully the inequality 2x2≥15−x", "options": ["x≤−3", "x≥2.5", "x≤−1.5, x≥5", "−1.5≤x≤5", "x≤−3, x≥2.5", "−3≤x≤2.5"], "answer": 4, "topic": "esat"}, {"id": "esat2017q5", "num": 5, "text": "ESAT 2017 Question 5", "question_text": "The equation gives y in terms of x : y=3(x2−1)2−5 Which one of the following is a rearrangement for x in terms of y ?", "options": ["x=2±2y−53√", "x=2±2y+53√", "x=2±3y+53√", "x=−2±2y+53√", "x=−2±3y+52√"], "answer": 1, "topic": "esat"}, {"id": "esat2017q6", "num": 6, "text": "ESAT 2017 Question 6", "question_text": "An electric motor is used to pull a broken-down car slowly from the road up a ramp on to the back of a breakdown truck. The car has a mass of 1200kg and is lifted through a vertical height of 1.0m . The total input energy to the motor is 28kJ and it is 75% efficient. In the process of lifting the car, energy is lost to the surroundings from the motor and from other causes. What is the total energy lost to the surroundings? ![45_382_618_1128_381_0.jpg](images/45_382_618_1128_381_0.jpg) (gravitati", "options": ["7.0kJ", "9.0kJ", "12kJ", "16kJ"], "answer": 3, "topic": "esat"}, {"id": "esat2017q7", "num": 7, "text": "ESAT 2017 Question 7", "question_text": "A fruit stall sells apples costing £x each, and pears costing £y each. Sam bought 2 apples and 5 pears, and the total cost of these was £P . Lesley bought 3 apples and 2 pears, and the total cost of these was £Q . Which of the following is an expression for the cost, in pounds (£), of a pear?", "options": ["2Q−3P3", "2Q−3P11", "Q−P3", "Q−P11", "P−Q3", "3P−2Q3", "3P−2Q11"], "answer": 6, "topic": "esat"}, {"id": "esat2017q8", "num": 8, "text": "ESAT 2017 Question 8", "question_text": "In one type of medical scanner a source is placed inside a patient's body. This source causes pairs of gamma-rays to be emitted simultaneously in opposite directions. Detectors on each side of the patient are used to detect the gamma-rays. The distance between the two detectors is 3.0m . When the source is at Q, half-way between the detectors, the two gamma-rays arrive at the same time. In a particular scan the gamma-rays arrive at the two detectors with a time difference of 4.0×10−10s . Assume ", "options": ["6.0mm", "12mm", "24mm", "6.0cm", "12cm", "24cm"], "answer": 3, "topic": "esat"}, {"id": "esat2017q9", "num": 9, "text": "ESAT 2017 Question 9", "question_text": "P is directly proportional to Q squared. When P is 2, Q is 4 . Q is inversely proportional to R . When Q is 2, R is 5 . What is P in terms of R ?", "options": ["P=5R", "P=54R", "P=1800R2", "P=54R2", "P=252R2", "P=800R2", "P=R250"], "answer": 4, "topic": "esat"}, {"id": "esat2017q10", "num": 10, "text": "ESAT 2017 Question 10", "question_text": "When a plutonium-239 nucleus absorbs a neutron it undergoes nuclear fission. One particular fission reaction results in the creation of xenon and zirconium as daughter nuclei. The nuclear equation for this reaction is shown but with some non-zero integers replaced by the letters w, x , y and z . 10n+23994Pu→w54Xe+yxZr+z10n Which equation is correct?", "options": ["w+y=240", "z=240−(w+y)", "x=40−z", "94=54+x+1", "240=54+x", "94=w+y+1"], "answer": 1, "topic": "esat"}, {"id": "esat2017q11", "num": 11, "text": "ESAT 2017 Question 11", "question_text": "Which one of the following is a simplification of 2−x2(9x2−4)x3(2−3x)", "options": ["−1−2x", "−1+2x", "5−2x", "5+2x", "5−3x", "5+3x"], "answer": 3, "topic": "esat"}, {"id": "esat2017q12", "num": 12, "text": "ESAT 2017 Question 12", "question_text": "An electric motor is connected to a constant 12V d.c. supply. The motor is used to lift a mass of 20kg by means of a rope and pulley. The mass is lifted vertically through a height of 6.0m in a time of 5.0s. The complete lifting system (motor, rope and pulley) is 80% efficient. ![49_705_306_438_424_0.jpg](images/49_705_306_438_424_0.jpg) What is the current in the electric motor? (gravitational field strength =10Nkg−1 )", "options": ["1.6A", "2.0A", "2.5A", "16A", "20A", "25A"], "answer": 5, "topic": "esat"}, {"id": "esat2017q13", "num": 13, "text": "ESAT 2017 Question 13", "question_text": "What is the value of x that makes the following expression correct? 23+2x4x8−x=42√", "options": ["-2.25", "-1.75", "-1.5", "-0.5", "-0.25"], "answer": 3, "topic": "esat"}, {"id": "esat2017q15", "num": 15, "text": "ESAT 2017 Question 15", "question_text": "There are 100 students in Year 10. Each student studies exactly one of French, German, and Spanish. X girls study French and there are 3X girls in total. 2Y boys study German. There are 35 students studying Spanish of which Y are boys. Which of the following is an expression for the total number of students studying German?", "options": ["X+2Y", "X+Y+35", "X+3Y−35", "2X+2Y", "2X+Y−35", "2X+3Y−35", "2X+Y+35"], "answer": 5, "topic": "esat"}, {"id": "esat2017q16", "num": 16, "text": "ESAT 2017 Question 16", "question_text": "The radius of an iron-56 atom is 3.0×104 times greater than the radius of an iron-56 nucleus. What is the value of density of an iron nucleus", "options": ["(3.0×104)−3", "(3.0×104)−2", "(3.0×104)−1", "(3.0×104)1"], "answer": 0, "topic": "esat"}, {"id": "esat2017q17", "num": 17, "text": "ESAT 2017 Question 17", "question_text": "An exterior angle of a regular polygon with n sides is 4° larger than an exterior angle of a regular polygon with (n+3) sides. What is the value of n ?", "options": ["10", "12", "15", "18", "21", "24", "27"], "answer": 2, "topic": "esat"}, {"id": "esat2017q20", "num": 20, "text": "ESAT 2017 Question 20", "question_text": "A kettle is designed to work from a car's power socket. The kettle has a power rating of 150 W when a constant voltage of 12.0V d.c. is applied across its element. How much charge passes through the element of this kettle when the voltage of 12.0 V is applied across it for 20minutes ?", "options": ["96C", "250C", "15000C", "36000C", "900000C", "2160000C"], "answer": 2, "topic": "esat"}, {"id": "esat2017q21", "num": 21, "text": "ESAT 2017 Question 21", "question_text": "The hands of a 12-hour analogue clock move continuously. When the time on the clock is 4:00, the angle between the minute hand and the hour hand is 120° . What is the angle between the two hands at 4:40?", "options": ["80°", "100°", "110°", "120°", "140°"], "answer": 1, "topic": "esat"}, {"id": "esat2017q22", "num": 22, "text": "ESAT 2017 Question 22", "question_text": "A freight train travelling on a straight horizontal track at 2.0ms−1 collides with a passenger train travelling at 5.0ms−1 in the opposite direction. Both trains immediately come to a complete stop on the track. The freight train has three locomotives of 130 tonnes each and seven container wagons of 30 tonnes each. The passenger train has two locomotives of 70 tonnes each and a number of passenger carriages of 10 tonnes each. How many passenger carriages does the passenger train have?", "options": ["7", "9", "10", "24", "46"], "answer": 2, "topic": "esat"}, {"id": "esat2017q26", "num": 26, "text": "ESAT 2017 Question 26", "question_text": "Two radioactive sources X and Y have half-lives of 3.0 hours and 2.0 hours respectively. The product of the decay of both of the sources is a stable isotope of the element Z. Six hours ago a mixture contained the same number of atoms of both X and Y, and no other atoms. What fraction of the mixture is now made up of atoms of Z?", "options": ["1016", "1116", "1216", "1316", "1416", "16"], "answer": 3, "topic": "esat"}, {"id": "esat2017q27", "num": 27, "text": "ESAT 2017 Question 27", "question_text": "A cylindrical hollow metal pipe is 16cm long. It has an external diameter of 10cm and an internal diameter of 8cm . The density of the metal from which the pipe is made is 8grams per cm3 . [diagram not to scale] ![58_450_428_646_489_0.jpg](images/58_450_428_646_489_0.jpg) What is the mass of the pipe in grams?", "options": ["8π", "16π", "18π", "72π", "128π", "512π", "1152π", "4608π"], "answer": 6, "topic": "esat"}, {"id": "esat2017q35", "num": 35, "text": "ESAT 2017 Question 35", "question_text": "The diagram shows the outline of a keyhole consisting of three straight sides and an arc from a circle. The sides PQ and RS are both 18mm in length and when extended meet at the centre of the circle O forming an angle of π6 radians. The longer arc from Q to R has length 22πmm . ![66_606_507_323_544_0.jpg](images/66_606_507_323_544_0.jpg) [diagram not to scale] What is the area, in mm2 , of the keyhole as shaded in the diagram?", "options": ["horizontal, uniform bar of mass 60kg is 4.0m long and is pivoted at one end. The bar is held in equilibrium by a force F at the other end of the bar, acting at an angle of 60° to the horizontal.", "121π+8413√4", "132π+2253√", "132π+2253√", "144π+225", "144π+2253√"], "answer": 2, "topic": "esat"}, {"id": "esat2017q37", "num": 37, "text": "ESAT 2017 Question 37", "question_text": "It is given that y=8p and z=(12)2q where p and q are real numbers. Which of the following expressions is a simplification of log2(y3z2) ?", "options": ["ball starts at a speed of 40.0ms−1 . The ball is subject to a constant deceleration of 14.4ms−2 as it travels a distance of 20.0m in a straight line.", "6p+4q", "6p−8q", "6p+8q", "9p−4q", "9p+4q", "9p−8q", "9p+8q"], "answer": 5, "topic": "esat"}, {"id": "esat2017q43", "num": 43, "text": "ESAT 2017 Question 43", "question_text": "Given that y=(2+3x)6 , what is the coefficient of x3 in dydx ?", "options": ["stone is fired vertically upwards at a speed of 13ms−1 on a still day from the top of a 6.0m high cliff. It then falls down and lands at the bottom of the cliff.", "4320", "4860", "12960", "19440"], "answer": 4, "topic": "esat"}, {"id": "esat2017q47", "num": 47, "text": "ESAT 2017 Question 47", "question_text": "The sequence of numbers u1, u2, u3,…, un,… is given by u1=2 un+1=pun+3 where p is an integer. The fourth term, u4 , is equal to -7 What is the value of u1+u2+u3+u4 ?", "options": ["-10", "-2", "-1", "8", "26"], "answer": 2, "topic": "esat"}, {"id": "esat2017q49", "num": 49, "text": "ESAT 2017 Question 49", "question_text": "Find the complete set of values of x for which x3−6x2+9x−4x>0", "options": ["A suitcase of mass m is on a conveyor belt which moves upwards at a constant speed at an angle of θ to the horizontal. The coefficient of friction between the suitcase and the slope is μ . The suitcase does not slip, even if angle θ is made slightly larger.", "0<x<4", "0<x<1, x>4", "x<0,1<x<4", "x<1, x>4", "1<x<4"], "answer": 0, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;

-- ESAT 2018 (21 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2018', 1, 2018, 'October', 80, 21, '["esat"]', '[{"id": "esat2018q1", "num": 1, "text": "ESAT 2018 Question 1", "question_text": "A group of drivers, consisting of 200 women and 300 men, was asked if they passed their driving test at the first attempt. Altogether 167 of the group said they passed at the first attempt. Of the women, 143 said they did not pass at the first attempt. How many of the men said they passed at the first attempt?", "options": ["10", "24", "33", "57", "110", "133", "157"], "answer": 4, "topic": "esat"}, {"id": "esat2018q2", "num": 2, "text": "ESAT 2018 Question 2", "question_text": "An unstable nucleus X becomes a stable nucleus Y after a succession of decays, during which a total of 5 alpha particles and 2 beta (β−) particles are emitted. How many fewer protons does nucleus Y contain than nucleus X?", "options": ["6", "8", "10", "12", "14", "16", "18", "20"], "answer": 1, "topic": "esat"}, {"id": "esat2018q3", "num": 3, "text": "ESAT 2018 Question 3", "question_text": "A cuboid has sides of length x,2√x and 2x , measured in cm. The volume, in cm3 , of the cuboid is numerically equal to twice the total surface area, in cm2 , of the cuboid. What is the value of x ?", "options": ["10", "6+22√", "5", "3+2√", "52", "32+122√"], "answer": 1, "topic": "esat"}, {"id": "esat2018q4", "num": 4, "text": "ESAT 2018 Question 4", "question_text": "The diagram shows three resistors R1, R2 and R3 connected in series with a battery of constant voltage. The resistance of each resistor and the corresponding current are also shown. ![84_624_267_436_527_0.jpg](images/84_624_267_436_527_0.jpg) Resistor R3 is now removed and the circuit is reconnected. What is the new current in the circuit?", "options": ["0.20 A", "0.22A", "0.33A", "0.40A", "0.50A", "2.0A", "6.0A"], "answer": 1, "topic": "esat"}, {"id": "esat2018q6", "num": 6, "text": "ESAT 2018 Question 6", "question_text": "When travelling in a vacuum, visible light has a wavelength between 400nm and 700nm . The speed of light in a vacuum is 3.0×108ms−1 . What can be concluded about ultraviolet radiation from this information?", "options": ["rectangle PQRS is drawn inside a circle, with its vertices on the circumference of the circle.", "It has a maximum frequency of 4.3×1014Hz", "It has a maximum frequency of 7.5×1014Hz", "It has a maximum frequency of 1.0×1015Hz", "It has a minimum frequency of 2.7×1014Hz", "It has a minimum frequency of 4.3×1014Hz", "It has a minimum frequency of 7.5×1014Hz", "It has a minimum frequency of 1.0×1015Hz"], "answer": 6, "topic": "esat"}, {"id": "esat2018q8", "num": 8, "text": "ESAT 2018 Question 8", "question_text": "A filament lamp working at its operating voltage converts electrical energy at a rate of 100W . The lamp has an efficiency of 5.0%. How much energy is wasted by the lamp in 10 minutes?", "options": ["50 J", "950J", "1000 J", "3000 J", "57000J", "60000J"], "answer": 4, "topic": "esat"}, {"id": "esat2018q10", "num": 10, "text": "ESAT 2018 Question 10", "question_text": "The potential difference across the motor in an electric car is 400V and the current in the motor is 1250 A. The car accelerates along a horizontal road from rest for 4.0s . The efficiency of the overall system is 45%. What is the kinetic energy of the car at the end of the 4.0 s? (Ignore energy losses due to air resistance and due to friction between the tyres and the road.)", "options": ["225000 J", "500000 J", "900000 J", "1250000 J", "2000000 J"], "answer": 2, "topic": "esat"}, {"id": "esat2018q11", "num": 11, "text": "ESAT 2018 Question 11", "question_text": "The straight lines 5x+2y=20 y=3x−23 x=0 enclose a region with area K square units. What is the value of K ?", "options": ["39", "78", "99", "129", "198", "258"], "answer": 2, "topic": "esat"}, {"id": "esat2018q12", "num": 12, "text": "ESAT 2018 Question 12", "question_text": "The momentum of a small object moving in a straight line is 24kgms−1 and its kinetic energy is 96J . What is the mass of the object?", "options": ["3.0kg", "4.0kg", "6.0kg", "8.0kg", "12kg"], "answer": 0, "topic": "esat"}, {"id": "esat2018q13", "num": 13, "text": "ESAT 2018 Question 13", "question_text": "A scale model of a cylindrical pillar is to be made. The full-sized pillar has a volume of 12πm3 . The model will use a length scale of 1:40 The model is to be a solid cylinder made of a plastic which has a density of 43gcm−3 . What is the mass of the model in grams?", "options": ["9640π", "140π", "40π", "11258π", "250π", "10000π", "225000π", "400000π"], "answer": 4, "topic": "esat"}, {"id": "esat2018q16", "num": 16, "text": "ESAT 2018 Question 16", "question_text": "A rock falling vertically experiences an air resistance force of 12 N at an instant when its acceleration is 2.0ms−2 downwards. What is the mass of the rock? (gravitational field strength =10Nkg−1 )", "options": ["1.0kg", "1.2kg", "1.5kg", "6.0kg", "10kg", "12kg", "15kg", "60 kg"], "answer": 2, "topic": "esat"}, {"id": "esat2018q18", "num": 18, "text": "ESAT 2018 Question 18", "question_text": "A transverse wave with an amplitude of 4.0 cm and a frequency of 10 Hz travels along a rope at a speed of 2.4ms−1 . What is the total distance travelled by a particle in the rope in a time of 20s ?", "options": ["2.4m", "4.8m", "8.0m", "16 m", "32m", "48m"], "answer": 4, "topic": "esat"}, {"id": "esat2018q19", "num": 19, "text": "ESAT 2018 Question 19", "question_text": "Q is 5km away from P on a bearing of 065° R is 5km away from Q on a bearing of 155° What is the bearing of P from R ?", "options": ["070°", "110°", "225°", "270°", "290°", "315°", "335°"], "answer": 4, "topic": "esat"}, {"id": "esat2018q20", "num": 20, "text": "ESAT 2018 Question 20", "question_text": "A student places a measuring cylinder on a balance. She pours a volume V of water into the measuring cylinder, and finds that the mass of the measuring cylinder and water together is 290g. She then empties the measuring cylinder and dries it before putting it back on the balance. She now pours the same volume V of olive oil into the measuring cylinder, and finds that the mass of the measuring cylinder and olive oil together is 270g . What is the mass of the measuring cylinder? (densities: olive ", "options": ["18g", "20g", "90 g", "180g", "200g"], "answer": 2, "topic": "esat"}, {"id": "esat2018q25", "num": 25, "text": "ESAT 2018 Question 25", "question_text": "The first five terms of a sequence in order are: 2174277122 The n th term of this sequence is pn2+q where p and q are integers. What is the value of p−qp+q ?", "options": ["14", "12", "1", "2317", "73", "2", "4", "14"], "answer": 6, "topic": "esat"}, {"id": "esat2018q37", "num": 37, "text": "ESAT 2018 Question 37", "question_text": "In a particular arithmetic progression: - the 13 th term is six times the 1 st term - the 11 th term is 1 less than twice the 5 th term What is the 3 rd term of the progression?", "options": ["-14.5", "-11", "29", "3.5", "11", "14.5"], "answer": 4, "topic": "esat"}, {"id": "esat2018q39", "num": 39, "text": "ESAT 2018 Question 39", "question_text": "The first three terms of a geometric progression, whose terms are all greater than zero, are (p−2),(2p+2) and (5p+14) What is the fifth term of the progression?", "options": ["324", "486", "1250", "1458", "3888"], "answer": 1, "topic": "esat"}, {"id": "esat2018q41", "num": 41, "text": "ESAT 2018 Question 41", "question_text": "Evaluate log2(54)+log2(65)+log2(76)+⋯+log2(6463)", "options": ["-2", "3", "4", "6", "log2(3!)", "log260"], "answer": 2, "topic": "esat"}, {"id": "esat2018q43", "num": 43, "text": "ESAT 2018 Question 43", "question_text": "Circle C has equation (x+3)2+(y−2)2=5 The length of the tangent from the circle C to the point P is 5/3 What is the shortest distance from P to C ?", "options": ["5", "5 3√+5√", "3 5√", "5", "10"], "answer": 2, "topic": "esat"}, {"id": "esat2018q47", "num": 47, "text": "ESAT 2018 Question 47", "question_text": "What is the coefficient of x3 in the expansion of (1−2x)5(1+2x)5 ?", "options": ["-6400", "-640", "-80", "0", "80", "800", "960"], "answer": 3, "topic": "esat"}, {"id": "esat2018q53", "num": 53, "text": "ESAT 2018 Question 53", "question_text": "The dimensions of a solid cuboid, in cm, are x,2x and y The volume of the cuboid is 576cm3 . At this volume, the surface area of the cuboid has its maximum value. What is the area, in cm2 , of the face that has the largest area?", "options": ["2(288)3", "72", "96", "432"], "answer": 2, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;

-- ESAT 2019 (21 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2019', 1, 2019, 'October', 80, 21, '["esat"]', '[{"id": "esat2019q1", "num": 1, "text": "ESAT 2019 Question 1", "question_text": "Evaluate (7√+3√)2−(7√−3√)2", "options": ["0", "27√", "47√", "221√", "10", "421√", "20"], "answer": 5, "topic": "esat"}, {"id": "esat2019q3", "num": 3, "text": "ESAT 2019 Question 3", "question_text": "The equation gives y in terms of x : y=3−4(1−x2)2 Which one of the following is a rearrangement for x in terms of y ?", "options": ["x=−2±23−y4√", "x=−2±24−y3√", "x=1±3−y4√", "x=1±23−y4√", "x=2±23−y4√", "x=2±24−y3√", "x=2±23+y4√"], "answer": 4, "topic": "esat"}, {"id": "esat2019q5", "num": 5, "text": "ESAT 2019 Question 5", "question_text": "The resistance to the motion of a car is directly proportional to the square of the speed of the car. The car increases its speed by 20%. What is the percentage increase in the resistance to the motion of the car?", "options": ["20%", "24%", "44%", "120%", "224%", "240%", "400%"], "answer": 2, "topic": "esat"}, {"id": "esat2019q6", "num": 6, "text": "ESAT 2019 Question 6", "question_text": "A water-tight cylinder with a thin, freely moving piston contains 2.0×10−3m3 of trapped air at atmospheric pressure of 1.0×105Pa . When the cylinder is submerged in water of constant density 1000kgm−3 , the volume of air in the cylinder decreases to 4.0×10−4m3 . The piston is at a depth ℎ below the surface of the water and the water surface is open to the atmosphere. What is the depth ℎ ? (gravitational field strength =10Nkg−1 ; assume that the temperature of the air remains constant and that ai", "options": ["40m", "50m", "60m", "400m", "500m", "600m"], "answer": 0, "topic": "esat"}, {"id": "esat2019q7", "num": 7, "text": "ESAT 2019 Question 7", "question_text": "The equation of a curve is y=px2+qx where p and q are constants. The curve passes through the points (2,6) and (4,−4) . What is the value of q−p ?", "options": ["1", "2", "5", "6", "9", "16"], "answer": 4, "topic": "esat"}, {"id": "esat2019q8", "num": 8, "text": "ESAT 2019 Question 8", "question_text": "The secondary coil of an ideal, 100% efficient transformer is connected to a resistor by cables of total resistance 1500Ω . The current in the primary coil is 4.0A . There are 240 turns in the primary coil and 4800 turns in the secondary coil. What is the power produced as heat in the cables?", "options": ["60 W", "300W", "6000 W", "24000W", "120000W", "9600000W"], "answer": 0, "topic": "esat"}, {"id": "esat2019q9", "num": 9, "text": "ESAT 2019 Question 9", "question_text": "Which of the following is a simplification of 4−x(3x+1)x2(3x2−2x−1)", "options": ["12x3−8x2−7x−1x(3x−1)(x−1)", "4x2+4x−1x(x+1)", "4x2+4x+1x(x+1)", "4x2−4x−1x(x−1)", "4x2−4x+1x(x−1)", "12x3−8x2−x+1x(3x−1)(x−1)"], "answer": 3, "topic": "esat"}, {"id": "esat2019q11", "num": 11, "text": "ESAT 2019 Question 11", "question_text": "The ball for a garden game is a solid sphere of volume 192cm3 . For the children's version of the game the ball is a solid sphere made of the same material, but the radius is reduced by 25%. What is the volume, in cm3 , of the children’s ball?", "options": ["48", "81", "96", "108", "144"], "answer": 1, "topic": "esat"}, {"id": "esat2019q12", "num": 12, "text": "ESAT 2019 Question 12", "question_text": "The radioactive isotope X becomes the stable isotope Y after a succession of decays involving only the emission of alpha and beta (β−) particles. During the decay of one nucleus from X to Y , a total of seven particles are emitted. It is known that more of these particles are alpha particles than beta particles. The atomic number of X is Z and the mass number of X is A . Which row in the table could give the atomic number and the mass number of Y? <table><tr><td></td><td>atomic number of Y</td><", "options": ["10", "12", "28", "36", "40", "54", "70"], "answer": 2, "topic": "esat"}, {"id": "esat2019q14", "num": 14, "text": "ESAT 2019 Question 14", "question_text": "The kinetic energy of an object of mass 4.0kg , travelling in a straight line, increases from 32J to 200J in 3.0 seconds due to a constant resultant force. What is the value of this resultant force?", "options": ["2.0N", "4.0N", "8.0N", "24N", "28 N", "56 N"], "answer": 2, "topic": "esat"}, {"id": "esat2019q15", "num": 15, "text": "ESAT 2019 Question 15", "question_text": "PR and QS are the diagonals of a rhombus PQRS. PR=(3x+2)cm QS=(8−2x)cm The area of PQRS is 11cm2 . What is the difference, in cm , between the two possible lengths of PR?", "options": ["223", "412", "513", "8", "14"], "answer": 3, "topic": "esat"}, {"id": "esat2019q18", "num": 18, "text": "ESAT 2019 Question 18", "question_text": "A block is designed with a cylindrical channel to accommodate a hot-water pipe. The block is 100 cm long and it has a square cross-section of side 22.0 cm with a cylindrical hole in the middle, as shown in the diagram: ![132_407_302_917_634_0.jpg](images/132_407_302_917_634_0.jpg) [diagram not to scale] The diameter of the cylindrical hole is 14.0cm and the density of the material from which the block is made is 0.100gcm−3 . What is the mass of the block? (take π to be 227 )", "options": ["1.32kg", "3.30kg", "13.2kg", "33.0kg", "132kg", "330kg", "1320kg", "3300kg"], "answer": 1, "topic": "esat"}, {"id": "esat2019q20", "num": 20, "text": "ESAT 2019 Question 20", "question_text": "A sample initially contains equal numbers of atoms of a radioactive isotope X and a stable isotope Y. Isotope X has a half-life of 3 years and decays in a single stage to the stable isotope Y. What is the ratio number of atoms of X : number of atoms of Y in the sample 6 years later?", "options": ["The sample contains only isotope Y.", "1:7", "1:4", "1:3", "7:4"], "answer": 1, "topic": "esat"}, {"id": "esat2019q21", "num": 21, "text": "ESAT 2019 Question 21", "question_text": "Find the area of the shape bounded by the four lines: 2y+x=4 x=−6 x=0 y=0", "options": ["4", "12", "21", "25", "27", "30"], "answer": 2, "topic": "esat"}, {"id": "esat2019q23", "num": 23, "text": "ESAT 2019 Question 23", "question_text": "The curve y=x3+px2+qx+r has a local maximum when x=−1 and a local minimum when x=3 What is the value of p ?", "options": ["-9", "-3", "-1", "1", "3", "9"], "answer": 1, "topic": "esat"}, {"id": "esat2019q25", "num": 25, "text": "ESAT 2019 Question 25", "question_text": "When simplified, 1(1−2√)3 is written in the form a+b2√ where a and b are integers. What is the value of b ?", "options": ["-7", "-5", "-1", "1", "5", "7"], "answer": 1, "topic": "esat"}, {"id": "esat2019q29", "num": 29, "text": "ESAT 2019 Question 29", "question_text": "An equilateral triangle of side 8cm is drawn so that its vertices lie on the circumference of a circle, as shown in the diagram. ![140_631_271_469_465_0.jpg](images/140_631_271_469_465_0.jpg) What is the total of the three areas shaded in the diagram, in cm2 ?", "options": ["8(2π−3)", "24(π−3√)", "48(4π−3√)", "163(4π−6−33√)", "163(4π−33√)"], "answer": 4, "topic": "esat"}, {"id": "esat2019q31", "num": 31, "text": "ESAT 2019 Question 31", "question_text": "Which one of the following is the real solution of the equation 3×52x+1−5x−2=0", "options": ["x=log5(13)", "x=log5(25)", "x=log5(35)", "x=log5(23)", "x=log5(53)", "x=log5(52)"], "answer": 1, "topic": "esat"}, {"id": "esat2019q26", "num": 26, "text": "ESAT 2019 Question 26", "question_text": "2835", "options": ["3024", "5670", "15120", "22680"], "answer": 2, "topic": "esat"}, {"id": "esat2019q37", "num": 37, "text": "ESAT 2019 Question 37", "question_text": "The three internal angles in a triangle are α,β and θ , and 3tan⁡α−2sin⁡β=2 5tan⁡α+6sin⁡β=8 What is the value of θ in degrees?", "options": ["15", "45", "75", "105", "135"], "answer": 3, "topic": "esat"}, {"id": "esat2019q39", "num": 39, "text": "ESAT 2019 Question 39", "question_text": "Find the complete set of values of x for which x3−2x2−7x−4>0", "options": ["x<−1", "x>−1", "−1<x<4", "x<−1 or x>4", "x<4", "x>4"], "answer": 5, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;

-- ESAT 2020 (20 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2020', 1, 2020, 'October', 80, 20, '["esat"]', '[{"id": "esat2020q1", "num": 1, "text": "ESAT 2020 Question 1", "question_text": "The admission charge to a cinema is different for adults and children. Admission for 2 adults and 3 children costs £20. Admission for 4 adults and 4 children costs £34. What does admission cost for 6 adults and 2 children?", "options": ["£27", "£29", "£33", "£39", "£44", "£848", "£72"], "answer": 3, "topic": "esat"}, {"id": "esat2020q2", "num": 2, "text": "ESAT 2020 Question 2", "question_text": "A soldering iron has a copper tip of mass 2.0 g. The tip is heated with 30W of thermal power. In 50s , the temperature of the tip increases by 200°C . How much energy is transferred from the tip to the surroundings in this time? (specific heat capacity of copper =400Jkg−1°C−1 )", "options": ["160J", "500J", "1340 J", "1500 J", "1660 J", "1840 J", "2500 J"], "answer": 2, "topic": "esat"}, {"id": "esat2020q3", "num": 3, "text": "ESAT 2020 Question 3", "question_text": "A fair spinner has eight equal sections. Each section has one number written on it, as shown. ![149_573_302_576_577_0.jpg](images/149_573_302_576_577_0.jpg) The spinner is spun twice, and the two numbers scored are added. What is the probability that the sum of the two numbers is 5?", "options": ["18", "58", "116", "316", "2564", "5564"], "answer": 0, "topic": "esat"}, {"id": "esat2020q4", "num": 4, "text": "ESAT 2020 Question 4", "question_text": "Uranium-238 (23892U) decays by a series of alpha and beta (β−) emissions to become the stable isotope lead-206 (20682Pb) . How many beta (β−) particles are emitted in the decay of one uranium-238 nucleus to lead-206?", "options": ["6", "8", "10", "12", "14", "16"], "answer": 0, "topic": "esat"}, {"id": "esat2020q5", "num": 5, "text": "ESAT 2020 Question 5", "question_text": "Consider the four lines with the following equations. 12x+6y=3 29y=3x−4 32y=6x+3 44x+6y−9=0 Which two lines are perpendicular?", "options": ["1 and 2", "1 and 3", "1 and 4", "2 and 3", "2 and 4", "3 and 4"], "answer": 1, "topic": "esat"}, {"id": "esat2020q10", "num": 10, "text": "ESAT 2020 Question 10", "question_text": "Two trolleys are moving towards each other along a straight horizontal track. One trolley has mass 8.0kg and is travelling to the right at 4.0ms−1 . The other trolley has mass 2.0kg and is travelling to the left at 1.0ms−1 . When the trolleys collide they stick together. How much kinetic energy is transferred to other forms of energy in the collision?", "options": ["2.0 J", "18 J", "20 J", "28 J", "35J", "40 J", "45 J", "65J"], "answer": 2, "topic": "esat"}, {"id": "esat2020q12", "num": 12, "text": "ESAT 2020 Question 12", "question_text": "A car of mass 800kg travels in a straight line along a horizontal road. The car accelerates non-uniformly from rest for 5.0 seconds and then moves at constant speed, as shown in the distance-time graph: ![155_300_370_1123_560_0.jpg](images/155_300_370_1123_560_0.jpg) What is the average resultant force acting on the car over the time for which it is accelerating?", "options": ["320N", "480N", "640N", "960N", "1600N", "3200N", "4800N"], "answer": 3, "topic": "esat"}, {"id": "esat2020q16", "num": 16, "text": "ESAT 2020 Question 16", "question_text": "A parachutist of mass 80.0kg drops from a plane travelling at 40.0ms−1,2000m above the Earth's surface. The parachutist hits the ground at a speed of 5.00ms−1 . How much work is done by the parachutist against drag forces during the fall? (Take the Earth’s gravitational field strength to be 10.0Nkg−1 .)", "options": ["1535000 J", "1624000J", "1649000J", "1663000J", "1726000J"], "answer": 3, "topic": "esat"}, {"id": "esat2020q17", "num": 17, "text": "ESAT 2020 Question 17", "question_text": "Two vertices of a square are at (1,1) and (3,5) . What is the difference between the perimeters of the largest and smallest possible squares that can be drawn with these points as two of their vertices?", "options": ["0", "43√(2−2√)", "43√(2√−1)", "45√(2−2√)", "45√(2√−1)", "413√(2−2√)", "413√(2√−1)", "43√5√(2−2√)"], "answer": 3, "topic": "esat"}, {"id": "esat2020q18", "num": 18, "text": "ESAT 2020 Question 18", "question_text": "A light spring of unstretched length 0.10m has a spring constant of 20Nm−1 . The spring is suspended so that it is vertical and a load of mass 0.050kg is attached to the end of the spring. The load is pulled vertically downwards until the length of the spring is 0.30m . The load is then released. What is the speed of the load at the instant that the spring returns to its unstretched length? (gravitational field strength =10Nkg−1 ; assume that resistive forces are negligible)", "options": ["0ms−1", "4.0ms−1", "6.0ms−1", "12ms−1", "16ms−1", "6√ms−1", "12√ms−1", "30√ms−1"], "answer": 6, "topic": "esat"}, {"id": "esat2020q19", "num": 19, "text": "ESAT 2020 Question 19", "question_text": "The quadratic equation 2x2−px−4=0 , where p is a positive constant, has two solutions that differ by 6 . What is the value of p ?", "options": ["2", "47√", "12", "411√", "434√", "630√"], "answer": 1, "topic": "esat"}, {"id": "esat2020q20", "num": 20, "text": "ESAT 2020 Question 20", "question_text": "A rocket travelling in space is burning its fuel at a constant rate. By expelling the burnt fuel through a nozzle, the engine is applying a constant force to the rocket. What is happening to the magnitude of the acceleration of the rocket?", "options": ["It is increasing at an increasing rate.", "It is increasing at a constant rate.", "It is increasing at a decreasing rate.", "It is not changing.", "It is decreasing at an increasing rate.", "It is decreasing at a constant rate.", "It is decreasing at a decreasing rate."], "answer": 0, "topic": "esat"}, {"id": "esat2020q21", "num": 21, "text": "ESAT 2020 Question 21", "question_text": "(x−1) and (x−2) are both factors of x4+ax3+bx2−12x+4 What are the values of a and b ?", "options": ["a=−6 and b=−23", "a=−6 and b=13", "a=6 and b=−11", "a=6 and b=1"], "answer": 1, "topic": "esat"}, {"id": "esat2020q23", "num": 23, "text": "ESAT 2020 Question 23", "question_text": "What is the area of the region enclosed between the curve y=12x2 , the line y=−x , and the lines x=1 and x=3 ?", "options": ["m", "−m", "4", "6", "253", "283"], "answer": 4, "topic": "esat"}, {"id": "esat2020q27", "num": 27, "text": "ESAT 2020 Question 27", "question_text": "The sum of the first 20 terms of an arithmetic progression is 50. The sum of the next 20 terms of the arithmetic progression is -50 . What is the sum of the first 100 terms of the arithmetic progression?", "options": ["-750", "-350", "-50", "−1598", "1598", "50", "350", "750"], "answer": 0, "topic": "esat"}, {"id": "esat2020q31", "num": 31, "text": "ESAT 2020 Question 31", "question_text": "P and Q are two different geometric progressions. The 3 rd term of each geometric progression is 4 . The 5 th term of each geometric progression is 2 . What is the modulus of the difference between the sums to infinity of P and Q ?", "options": ["0", "8", "82√", "16", "162√", "32", "322√"], "answer": 4, "topic": "esat"}, {"id": "esat2020q33", "num": 33, "text": "ESAT 2020 Question 33", "question_text": "The curve y=x3+35√px2+3px+13 has two distinct turning points. What are all the possible values of p ?", "options": ["p<0, p>0.2", "p≤0, p≥0.2", "0<p<0.2", "0≤p≤0.2", "p<0, p>1.2", "p≤0, p≥1.2", "0<p<1.2", "0≤p≤1.2"], "answer": 0, "topic": "esat"}, {"id": "esat2020q35", "num": 35, "text": "ESAT 2020 Question 35", "question_text": "Find the number of solutions of the equation 14cos3x+10sin2xcos⁡x=13cos⁡x in the range −2π≤x≤2π", "options": ["4", "6", "8", "10", "12", "14"], "answer": 4, "topic": "esat"}, {"id": "esat2020q37", "num": 37, "text": "ESAT 2020 Question 37", "question_text": "Find the product of the real roots of the equation (log10x2)2+log10x=3", "options": ["10−32", "10−1", "10−12", "10−14", "1035", "101"], "answer": 3, "topic": "esat"}, {"id": "esat2020q9", "num": 9, "text": "ESAT 2020 Question 9", "question_text": "Find the maximum value of the gradient of the curve with equation y=2−4x+4x32−x2 where x>0", "options": ["-4", "−89", "12", "2", "4"], "answer": 0, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;

-- ESAT 2021 (13 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2021', 1, 2021, 'October', 80, 13, '["esat"]', '[{"id": "esat2021q2", "num": 2, "text": "ESAT 2021 Question 2", "question_text": "Air is trapped in a cylinder by a piston. The density of the air in the cylinder is ρ . ![175_324_271_1080_294_0.jpg](images/175_324_271_1080_294_0.jpg) The piston is moved so that the pressure of the trapped air increases by 20%. The temperature of the trapped air does not change. What is the new density of the trapped air? (Assume that air is an ideal gas.)", "options": ["0.69ρ", "0.80ρ", "0.83ρ", "1.00ρ", "1.20ρ", "1.44ρ"], "answer": 4, "topic": "esat"}, {"id": "esat2021q4", "num": 4, "text": "ESAT 2021 Question 4", "question_text": "A non-ideal transformer has 100 turns on the primary coil and 25 turns on the secondary coil. It is provided with 3.0kW of electrical power at a current of 12.5A . The voltage output is the same as for an ideal transformer, but the current in the output coil is 40 A. What is the efficiency of the transformer?", "options": ["20%", "25%", "31%", "69%", "75%", "80%", "91%", "100%"], "answer": 5, "topic": "esat"}, {"id": "esat2021q6", "num": 6, "text": "ESAT 2021 Question 6", "question_text": "A light spring has an uncompressed length of 0.10m . When an object of mass 0.5kg rests in equilibrium on top of the spring, the length of the spring reduces to 0.08m as shown. ![179_410_269_908_267_0.jpg](images/179_410_269_908_267_0.jpg) What is the energy stored in the spring due to the compression? (gravitational field strength =10Nkg−1 ; the spring obeys Hooke’s law)", "options": ["0.005 J", "0.02 J", "0.05 J", "0.1 J", "0.2 J", "0.4 J"], "answer": 2, "topic": "esat"}, {"id": "esat2021q8", "num": 8, "text": "ESAT 2021 Question 8", "question_text": "A set of decorative lights consists of 20 lamps connected in series to a dc supply of constant voltage. The total power transferred by all the lamps is P . The set is designed so that if one of the lamps fails, that lamp becomes short-circuited and it then has zero resistance. The remaining lamps are still lit. If this happens, with the set connected to the same supply, what is the new total power transferred by the remaining 19 lamps? (Assume that the resistance of each functioning lamp remains", "options": ["(1920)2P", "(1920)P", "P", "(2019)P", "(2019)2P"], "answer": 3, "topic": "esat"}, {"id": "esat2021q10", "num": 10, "text": "ESAT 2021 Question 10", "question_text": "A train accelerates from rest along a straight, horizontal section of track. The force exerted on the train due to its motors is constant and there is a constant friction force of 1.8×107N . The graph shows how the momentum of the train changes with time. momentum / 106kgms−1 ![182_551_444_745_781_0.jpg](images/182_551_444_745_781_0.jpg) What is the force exerted on the train due to its motors?", "options": ["3.0×106N", "6.0×106N", "1.2×107N", "1.5×107N", "2.1×107N", "2.4×107N", "3.0×107N", "4.2×107N"], "answer": 4, "topic": "esat"}, {"id": "esat2021q11", "num": 11, "text": "ESAT 2021 Question 11", "question_text": "The curve with equation y=x2−4x+5 meets the straight line with equation y=2x+c at two points, which have x -coordinates p and q , where q>p . Given that q−p=8 , what is the value of the constant c ?", "options": ["-43", "-12", "-2", "0", "2", "12", "43"], "answer": 5, "topic": "esat"}, {"id": "esat2021q12", "num": 12, "text": "ESAT 2021 Question 12", "question_text": "A ship travels into a wave that is travelling in the opposite direction to the ship. The ship has a horizontal speed of 8.0ms−1 . The speed of the wave is 3.0ms−1 . The front of the ship rises and falls with a time period of 8.0s . What is the wavelength of the wave?", "options": ["38m", "58m", "1.0m", "118m", "24m", "40m", "64m", "88m"], "answer": 7, "topic": "esat"}, {"id": "esat2021q18", "num": 18, "text": "ESAT 2021 Question 18", "question_text": "A beaker containing 180g of water at 25°C has a 20g ice cube at 0°C added to it. No heat is transferred between the water and the surroundings (including the beaker). What is the final temperature of all the water in the beaker after all the ice has melted? (Take the specific heat capacity of water to be 4Jg−1°C−1 and the specific latent heat of fusion of water to be 300Jg−1 .)", "options": ["2.5°C", "8.3°C", "10.0°C", "15.0°C", "16.7°C", "22.5°C"], "answer": 3, "topic": "esat"}, {"id": "esat2021q20", "num": 20, "text": "ESAT 2021 Question 20", "question_text": "A pulse of ultrasound travels from one end of a solid uniform rod of length L , starting at time t=0 . The pulse is partially reflected by a crack in the rod and partially by the far end of the rod. These two reflected pulses travel back along the rod, arriving at the end from which they started at times t1 and t2 , where t2>t1 . What is the distance between the crack and the far end of the rod?", "options": ["t1t2 L", "t2t1 L", "t12t2 L", "t22t1 L", "(t2−t1)t2L", "(t2−t1)2t2L"], "answer": 4, "topic": "esat"}, {"id": "esat2021q23", "num": 23, "text": "ESAT 2021 Question 23", "question_text": "A particular arithmetic series has first term a and common difference d . The sum of the first k terms of this series is denoted by Sk Which of the following is a simplification of Sn+1−Sn−1 ?", "options": ["d", "2d", "2a+d", "2a+2d", "2a+nd", "2a+2nd", "2a+(2n−1)d", "2a+(4n−2)d"], "answer": 6, "topic": "esat"}, {"id": "esat2021q27", "num": 27, "text": "ESAT 2021 Question 27", "question_text": "The line x=1 divides the circle x2+y2=4 into two segments. What is the area of the smaller segment?", "options": ["2π3−3√2", "2π3−3√", "π2−12", "π2−1", "π−12", "π−1", "4π3−3√2", "4π3−3√"], "answer": 7, "topic": "esat"}, {"id": "esat2021q31", "num": 31, "text": "ESAT 2021 Question 31", "question_text": "Which of the following is the largest in value? (All angles are in radians.)", "options": ["cos 0.5", "cos0.75", "cos⁡1", "sin0.5", "sin 0.75", "sin⁡1"], "answer": 0, "topic": "esat"}, {"id": "esat2021q35", "num": 35, "text": "ESAT 2021 Question 35", "question_text": "At how many distinct points do the following two curves meet? y=(x−4)(x2−2x−8) y=−x2+8x−16", "options": ["0", "1", "2", "3", "4", "5"], "answer": 2, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;

-- ESAT 2022 (14 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2022', 1, 2022, 'October', 80, 14, '["esat"]', '[{"id": "esat2022q2", "num": 2, "text": "ESAT 2022 Question 2", "question_text": "There is a constant current in a conducting wire. A charge of 20C passes through the wire in 1.5 minutes. An 18cm straight section of this wire lies in a uniform magnetic field. This section of wire is perpendicular to the direction of the field. The magnetic field strength is 0.15T . What is the magnitude of the magnetic force on this section of wire?", "options": ["0.0060N", "0.36N", "0.60N", "0.81N", "36N", "49N", "81N", "4900 N"], "answer": 0, "topic": "esat"}, {"id": "esat2022q4", "num": 4, "text": "ESAT 2022 Question 4", "question_text": "Two identical resistors are connected in parallel to a 6.0 V battery. The two resistors dissipate a total power of 0.15 W. One of these resistors is removed from the circuit and connected to a 12 V battery. How much charge passes through this resistor in 6.0 minutes?", "options": ["0.025 C", "0.050 C", "0.15C", "0.30C", "0.75C", "1.5C", "9.0C", "18C"], "answer": 6, "topic": "esat"}, {"id": "esat2022q5", "num": 5, "text": "ESAT 2022 Question 5", "question_text": "Rob keeps a record of what he earns each day. On Monday, he earned 50% less than he earned on Sunday. On Tuesday, he earned 20% more than he earned on Monday. On Wednesday, he earned 30% less than he earned on Tuesday. On Wednesday, he earned £84. How much did Rob earn on Sunday?", "options": ["£15.12", "£35.28", "£117.60", "£200", "£210", "£300", "£1200"], "answer": 3, "topic": "esat"}, {"id": "esat2022q6", "num": 6, "text": "ESAT 2022 Question 6", "question_text": "Ultrasound is used to find a crack inside a cuboid block of metal. An ultrasound probe is held in contact with the top surface of the metal block and perpendicular to the surface. A short pulse of ultrasound is sent into the metal block at time t=0ms and reflects from both the crack and the bottom surface of the metal block. ![208_768_340_418_248_0.jpg](images/208_768_340_418_248_0.jpg) The times between the emission of the ultrasound pulse and the return of the reflections to the probe, and the", "options": ["0.2m", "0.3m", "0.4m", "0.5m", "0.6m", "1.0m"], "answer": 0, "topic": "esat"}, {"id": "esat2022q8", "num": 8, "text": "ESAT 2022 Question 8", "question_text": "Power is supplied to an electric motor at 0.800kW . The motor has an efficiency of 60% and is switched on for half an hour. How much energy is wasted during this time?", "options": ["larger rectangle is made by adding 3cm to both the length and the width of PQRS, as shown.", "0.240 J", "160 J", "240 J", "576J", "864J", "576000J", "864000J"], "answer": 6, "topic": "esat"}, {"id": "esat2022q14", "num": 14, "text": "ESAT 2022 Question 14", "question_text": "A piece of metal of mass 50g is at thermal equilibrium in a hot liquid at temperature T . The metal is removed from the liquid and immediately placed in 100g of water that is at 20°C . The water is stirred and reaches a final temperature of 26°C . <table><tr><td>material</td><td>specific heat capacity /Jkg−1°C−1</td></tr><tr><td>hot liquid</td><td>2000</td></tr><tr><td>metal</td><td>350</td></tr><tr><td>water</td><td>4200</td></tr></table> What is the temperature T of the hot liquid? (Assume tha", "options": ["38°C", "51°C", "150°C", "170°C", "480°C"], "answer": 3, "topic": "esat"}, {"id": "esat2022q15", "num": 15, "text": "ESAT 2022 Question 15", "question_text": "The variables x and y are related by the equation: x=5−2y3+11−2y3 Which of the following is a rearrangement to make y the subject?", "options": ["y=x−48x−483√", "y=x−68x−323√", "y=x−2x−63√", "y=x−3x−43√", "y=x−42x−123√", "y=x−62x−83√"], "answer": 4, "topic": "esat"}, {"id": "esat2022q17", "num": 17, "text": "ESAT 2022 Question 17", "question_text": "Three different numbers are chosen at random from 1√,2√,3√,4√,5√ . What is the probability that the three numbers form the three sides of a right-angled triangle?", "options": ["115", "110", "310", "13", "25", "23", "45"], "answer": 4, "topic": "esat"}, {"id": "esat2022q18", "num": 18, "text": "ESAT 2022 Question 18", "question_text": "A small slider of mass 30g is at rest near the bottom of a frictionless slope and in contact with a light uncompressed spring as shown. ![219_533_264_660_313_0.jpg](images/219_533_264_660_313_0.jpg) [diagram not to scale] The spring is compressed by 5.0cm and the slider remains in contact with it. The spring is released and causes the slider to rise up the slope to a maximum vertical height of 20cm . The slider is replaced with one of mass 20g . The spring is now compressed by 15cm , and the new", "options": ["40cm", "60cm", "90cm", "120cm", "180cm", "270cm"], "answer": 5, "topic": "esat"}, {"id": "esat2022q19", "num": 19, "text": "ESAT 2022 Question 19", "question_text": "The point (−1,5) is translated to the point (3,2) by two successive translations. The first translation is by the vector (3p−4p) The second translation is by the vector (q−2q) What is the value of p+q ?", "options": ["-14", "-7", "-5", "-1", "1", "5", "7", "14"], "answer": 3, "topic": "esat"}, {"id": "esat2022q25", "num": 25, "text": "ESAT 2022 Question 25", "question_text": "Four mathematically similar solids, W, X, Y and Z, have the following properties: - The ratio of the lengths of W to the lengths of X is 1:2 - The ratio of the surface area of X to the surface area of Y is 2:1 - The ratio of the volume of Y to the volume of Z is 1:2 What is the order of the solids when arranged in increasing volume?", "options": ["WYXZ", "WYZX", "WZYX", "YWXZ", "YWZX", "YZWX"], "answer": 1, "topic": "esat"}, {"id": "esat2022q31", "num": 31, "text": "ESAT 2022 Question 31", "question_text": "What is the complete set of real values of x for which x2(x2+4)<21", "options": ["−3√<x<3√", "−7√<x<7√", "x<−3√ or x>3√", "x<−7√ or x>7√", "−7√<x<−3√ or 3√<x<7√", "x<−7√ or −3√<x<3√ or x>7√"], "answer": 0, "topic": "esat"}, {"id": "esat2022q33", "num": 33, "text": "ESAT 2022 Question 33", "question_text": "A sector of a circle has perimeter 24. For what value of the radius does the sector have the maximum possible area?", "options": ["32√", "26√", "36√", "6", "12", "18", "36"], "answer": 3, "topic": "esat"}, {"id": "esat2022q35", "num": 35, "text": "ESAT 2022 Question 35", "question_text": "The curve y=x2−x−6 intersects the x -axis at the points A and B , and has a minimum at the point C . The rectangle ABDE has two of its vertices at A and B . The point C lies on the edge DE , between D and E . What is the area of the rectangle ABDE ?", "options": ["55a", "5√2a", "25√5a", "45√5a", "310√5a", "36.75", "42", "43.75"], "answer": 3, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;

-- ESAT 2023 (17 questions)
INSERT INTO papers (title, paper_number, year, sitting, duration_minutes, total_marks, topics, questions)
VALUES ('ESAT 2023', 1, 2023, 'October', 80, 17, '["esat"]', '[{"id": "esat2023q1", "num": 1, "text": "ESAT 2023 Question 1", "question_text": "The surface area of a solid sphere of radius R is equal to the total surface area of 10 solid closed cylinders of radius r and height 4r . Which of the following is an expression for R in terms of r ? (The surface area of a sphere of radius R is 4πR2 .) AR=5r", "options": ["R=12r", "R=25√r", "R=1210√r", "R=10√r", "R=3210√r", "R=15√r"], "answer": 0, "topic": "esat"}, {"id": "esat2023q2", "num": 2, "text": "ESAT 2023 Question 2", "question_text": "A spaceship of mass 10000kg is moving at 2.0ms−1 relative to a space station. The spaceship is captured by a robotic arm attached to the space station and brought to rest by a force of 1000N . How far will the spaceship move in its initial direction relative to the space station while the force is being applied? (Assume that the acceleration of the space station is negligible.)", "options": ["0.050m", "0.10m", "0.20m", "5.0m", "10m", "20m"], "answer": 5, "topic": "esat"}, {"id": "esat2023q3", "num": 3, "text": "ESAT 2023 Question 3", "question_text": "Which of the following is a correct rearrangement of y=p−q−rs−x to make x the subject?", "options": ["x=s−q−rp+y", "x=q−rp+y−s", "x=s−q−rp−y", "x=q−rp−y−s", "x=s−q−ry−p"], "answer": 2, "topic": "esat"}, {"id": "esat2023q4", "num": 4, "text": "ESAT 2023 Question 4", "question_text": "A circuit is set up as shown. All three resistors are identical. When the switch is open, the reading on the ammeter is 1.0 A and the power transferred from the battery is 1.0 W. ![236_580_335_567_335_0.jpg](images/236_580_335_567_335_0.jpg) The switch is now closed. What is the new reading on the ammeter and what is the new power transferred from the battery? <table><tr><td></td><td>ammeter reading I A</td><td>power transferred / W</td></tr><tr><td>A</td><td>0.67</td><td>0.67</td></tr><tr><td>B", "options": ["13", "25", "920", "130", "1960", "2360"], "answer": 5, "topic": "esat"}, {"id": "esat2023q6", "num": 6, "text": "ESAT 2023 Question 6", "question_text": "A spring is initially unstretched. A force F is used to stretch the spring. The extension x and the energy E stored in the stretched spring are measured for different values of F . The graph shows how the energy E , in J , varies with the extension squared, x2 , in cm2 . ![238_534_342_544_398_0.jpg](images/238_534_342_544_398_0.jpg) What is the magnitude of F when the spring stores 0.015J of energy?", "options": ["0.30N", "0.60N", "1.2N", "1.5N", "2.4N", "3.0N", "30N", "60N"], "answer": 1, "topic": "esat"}, {"id": "esat2023q7", "num": 7, "text": "ESAT 2023 Question 7", "question_text": "Given that 272(x−2)9(2x−3)=(81)32 what is the value of x ?", "options": ["0", "2.5", "3", "6", "7.5", "9", "10.5", "12"], "answer": 3, "topic": "esat"}, {"id": "esat2023q8", "num": 8, "text": "ESAT 2023 Question 8", "question_text": "A solid, cylindrical metal bar has a uniform cross-sectional area of 12cm2 and a volume of 180cm3 . The bar rests on a horizontal surface on one of its circular faces. The pressure on the surface due to the bar is 0.45Ncm−2 . What is the density of the metal, in gcm−3 ? (gravitational field strength =10Nkg−1 )", "options": ["2.5gcm−3", "3.0gcm−3", "3.75gcm−3", "7.5gcm−3", "15gcm−3", "33gcm−3"], "answer": 1, "topic": "esat"}, {"id": "esat2023q9", "num": 9, "text": "ESAT 2023 Question 9", "question_text": "Last year, the salary of the coach of a football club was 80% of the salary of the star player. At the start of the new year, the coach received a 15% increase in salary and the star player received a 38% increase in salary. What percentage of the star player's new salary is the coach's new salary?", "options": ["46%", "57%", "6135%", "6623%", "77%", "83 13%"], "answer": 3, "topic": "esat"}, {"id": "esat2023q10", "num": 10, "text": "ESAT 2023 Question 10", "question_text": "Two samples of pure radioactive isotopes X and Y decay with half-lives of 2 days and 3 days, respectively. Both X and Y decay in a single step into different stable isotopes. Initially the number of atoms of X is twice the number of atoms of Y . After how many days are the expected numbers of atoms of X and Y equal to each other?", "options": ["The expected numbers of atoms of X and Y are never equal.", "2 days", "3 days", "4 days", "6 days", "12 days"], "answer": 4, "topic": "esat"}, {"id": "esat2023q11", "num": 11, "text": "ESAT 2023 Question 11", "question_text": "An athlete's training session consists of several complete repetitions of a three-part programme: 1. Walk 100m at an average speed of 6kmh−1 2. Jog 200 m at an average speed of 10kmh−1 3. Run 100m at an average speed of 20kmh−1 What is the athlete’s average speed for the complete training session, in kmh−1 ?", "options": ["7.2", "9.6", "11.5", "12", "14.4"], "answer": 1, "topic": "esat"}, {"id": "esat2023q14", "num": 14, "text": "ESAT 2023 Question 14", "question_text": "The voltage output of a power station is stepped up using a transformer before the power is transmitted to a distant town. The primary coil of this transformer has 300 turns and the secondary coil has 1500 turns. In the town, a step-down transformer reduces the voltage supplied by the transmission cables to 33000V for distribution within the town. The step-down transformer supplies a current of 1500 A. The current in the transmission cables is 450A and both transformers are ideal and 100% effici", "options": ["1980V", "6600V", "22000 V", "110000 V", "550000 V"], "answer": 2, "topic": "esat"}, {"id": "esat2023q15", "num": 15, "text": "ESAT 2023 Question 15", "question_text": "The equation (a×104+2a×1033×10−1)2=8×109 has two solutions for a . What is the positive difference between these two solutions?", "options": ["0", "25√", "45√", "205√", "405√", "2005√"], "answer": 1, "topic": "esat"}, {"id": "esat2023q16", "num": 16, "text": "ESAT 2023 Question 16", "question_text": "A transverse wave with an amplitude of 3.0cm travels along a stretched string. The wave has a frequency of 12Hz and a wavelength of 0.25m . What is the average speed of a particle in the string as the string oscillates during a time of 2.0s?", "options": ["36cms−1", "72cms−1", "125cms−1", "144cms−1", "300cms−1"], "answer": 3, "topic": "esat"}, {"id": "esat2023q20", "num": 20, "text": "ESAT 2023 Question 20", "question_text": "A diver at the bottom of a lake of depth d fills a syringe with an ideal gas and seals the nozzle. The piston remains free to move. The volume of the gas in the syringe at the bottom of the lake is 90cm3 . As the diver returns to the surface, the temperature of the gas does not change. At the surface of the lake the gas in the syringe is at atmospheric pressure and the volume of the gas is 720cm3 . What is the volume of the gas in the syringe at a depth d2 ?", "options": ["160cm3", "180cm3", "206cm3", "225cm3", "288cm3", "315cm3", "360cm3", "405cm3"], "answer": 0, "topic": "esat"}, {"id": "esat2023q21", "num": 21, "text": "ESAT 2023 Question 21", "question_text": "x2−x−6 is a factor of x3+ax2+2x+b , where a and b are real constants. What is the value of a+b ?", "options": ["-39", "-21", "-3", "−35", "5", "3", "21", "39"], "answer": 7, "topic": "esat"}, {"id": "esat2023q23", "num": 23, "text": "ESAT 2023 Question 23", "question_text": "An arithmetic progression has first term a and common difference d . The sum of the first 9 terms plus the sum of the first 10 terms is equal to the sum of the first 11 terms. Which of the following is a correct expression for a in terms of d ?", "options": ["a=−134d", "a=−154d", "a=−163d", "a=−193d", "a=−7d", "a=−8d"], "answer": 0, "topic": "esat"}, {"id": "esat2023q5", "num": 5, "text": "ESAT 2023 Question 5", "question_text": "The first three terms of a convergent geometric progression are: 2p, p−3, p−7 What is the sum to infinity of this progression?", "options": ["-54", "-27", "−1312", "-2", "2", "13", "27", "54"], "answer": 5, "topic": "esat"}]')
ON CONFLICT (id) DO UPDATE SET questions = EXCLUDED.questions;
